import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void chargeDisputeResolveRefund() {
        assertEquals("REFUNDED",
                new Solution().finalState(new String[]{"CHARGE", "DISPUTE", "RESOLVE", "REFUND"}));
    }

    @Test
    void terminalRefundedIgnoresDisput() {
        // REFUNDED is terminal: DISPUTE after REFUND is a no-op
        assertEquals("REFUNDED",
                new Solution().finalState(new String[]{"CHARGE", "REFUND", "DISPUTE"}));
    }

    @Test
    void emptyEvents() {
        assertEquals("PENDING",
                new Solution().finalState(new String[]{}));
    }

    @Test
    void noOpFromPending() {
        // DISPUTE and REFUND are no-ops when state is PENDING
        assertEquals("PENDING",
                new Solution().finalState(new String[]{"DISPUTE", "REFUND"}));
    }

    @Test
    void chargeOnly() {
        assertEquals("CHARGED",
                new Solution().finalState(new String[]{"CHARGE"}));
    }

    @Test
    void disputeResolvedMultipleTimes() {
        // CHARGE → DISPUTED → CHARGED → DISPUTED (second dispute)
        assertEquals("DISPUTED",
                new Solution().finalState(new String[]{"CHARGE", "DISPUTE", "RESOLVE", "DISPUTE"}));
    }

    @Test
    void unknownEventIsNoOp() {
        // Unknown event "CANCEL" should not throw and should be a no-op
        assertEquals("CHARGED",
                new Solution().finalState(new String[]{"CHARGE", "CANCEL"}));
    }
}
